                    <div class="d-flex justify-content-between align-items-center mt-2">
                        <div class="QuantityArea" IncrDecrArea>
                            <button class="QuantityToggler" DecrementBtn>-</button>
                            <span class="Quantity" QuantityText>1</span>
                            <button class="QuantityToggler" IncrementBtn>+</button>
                        </div>
                        <strong class="ItemPrice" ItemPrice>$3,999.00</strong>
                    </div>
